# WRITE ALL FILES
# ============================================================
def write_json(filename, data):
    path = os.path.join(DATA_DIR, filename)
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f"{filename}: {len(data)} entries written")

write_json('talents.json', talents)
write_json('advantages.json', advantages)
write_json('disadvantages.json', disadvantages)
write_json('special-abilities.json', special_abilities)

print("Done! All 4 files written.")
